51	    engine: &Engine,
52	    pkg_dep_graph: &PackageGraph,
53	    changed_files: &HashSet<AnchoredSystemPathBuf>,
54	    global_deps: &[String],
55	) -> HashSet<TaskId<'static>> {
56	    if is_global_change(changed_files, global_deps, pkg_dep_graph) {
57	        return engine.task_ids().cloned().collect();
58	    }
59	
60	    turborepo_engine::match_tasks_against_changed_files(engine, pkg_dep_graph, changed_files)
61	        .into_keys()
