65	/// Returns `true` if any changed file is a global dependency, meaning all
66	/// tasks should be considered affected regardless of their individual inputs.
67	///
68	/// Global changes include:
69	/// - Root config files: `package.json`, `turbo.json`, `turbo.jsonc`
70	/// - The package manager's lockfile
71	/// - Files matching user-configured `globalDependencies` globs
72	fn is_global_change(
73	    changed_files: &HashSet<AnchoredSystemPathBuf>,
74	    global_deps: &[String],
75	    pkg_dep_graph: &PackageGraph,
76	) -> bool {
77	    let lockfile_name = pkg_dep_graph.package_manager().lockfile_name();
78	    let global_globs: Vec<_> = global_deps
79	        .iter()
80	        .filter_map(|g| match wax::Glob::new(g) {
81	            Ok(glob) => Some(glob),
82	            Err(e) => {
83	                tracing::warn!(
84	                    glob = %g,
85	                    error = %e,
86	                    "invalid globalDependency glob; ignoring for affected detection"
87	                );
88	                None
89	            }
90	        })
91	        .collect();
92	    let global_deps_matcher = wax::any(global_globs).ok();
93	
94	    for file in changed_files {
95	        let file_str = file.as_str();
96	
97	        if DEFAULT_GLOBAL_DEPS.contains(&file_str) {
98	            return true;
99	        }
100	
101	        if file_str == lockfile_name {
102	            return true;
103	        }
104	
105	        if let Some(ref matcher) = global_deps_matcher {
106	            if matcher.is_match(file_str) {
107	                return true;
108	            }
109	        }
110	    }
111	
112	    false
113	}
