1	//! Task-level filter resolution for `--filter` with the `filterUsingTasks`
2	//! future flag.
3	//!
4	//! When active, `--filter` patterns are resolved against the task graph
5	//! rather than the package graph:
6	//!
7	//! - Git-range selectors (`[main]`) match changed files against each task's
8	//!   `inputs` globs, catching out-of-package inputs like `$TURBO_ROOT$`.
9	//! - The `...` dependency/dependent syntax traverses the task graph, picking up
10	//!   cross-package task dependencies (e.g. `web#build -> schema#gen` where
11	//!   `web` has no package-level dependency on `schema`).
12	//!
13	//! The core matching logic reuses
14	//! `turborepo_engine::match_tasks_against_changed_files`
15	//! and `crate::task_change_detector::affected_task_ids`, sharing code with
16	//! `--affected` + `affectedUsingTaskInputs`.
17	
18	use std::collections::HashSet;
19	
20	use turbopath::{AbsoluteSystemPath, AnchoredSystemPathBuf};
21	use turborepo_repository::package_graph::{PackageGraph, PackageName};
22	use turborepo_scm::SCM;
23	use turborepo_scope::{target_selector::GitRange, TargetSelector};
24	use turborepo_task_id::TaskId;
25	use wax::Program;
26	
27	use crate::engine::Engine;
28	
29	/// Filters an engine down to only the tasks matching the given selectors.
30	///
31	/// Each include selector contributes a set of tasks (unioned together).
32	/// Exclude selectors remove tasks from the result. After all selectors
33	/// are processed, the engine is pruned to the surviving tasks plus their
34	/// transitive dependents (so downstream tasks still run).
35	pub fn filter_engine_to_tasks(
36	    engine: Engine,
37	    selectors: &[TargetSelector],
38	    pkg_dep_graph: &PackageGraph,
39	    scm: &SCM,
40	    repo_root: &AbsoluteSystemPath,
41	    global_deps: &[String],
42	) -> Result<Engine, crate::run::error::Error> {
43	    let (include, exclude): (Vec<_>, Vec<_>) = selectors.iter().partition(|s| !s.exclude);
44	
45	    let mut included_tasks: HashSet<TaskId<'static>> = HashSet::new();
46	
47	    for selector in &include {
48	        let matched = resolve_selector_to_tasks(
49	            &engine,
50	            selector,
51	            pkg_dep_graph,
52	            scm,
53	            repo_root,
54	            global_deps,
55	        )?;
56	        included_tasks.extend(matched);
57	    }
58	
59	    // If there were no include selectors (only excludes), start with all tasks.
60	    if include.is_empty() {
61	        included_tasks = engine.task_ids().cloned().collect();
62	    }
63	
64	    for selector in &exclude {
65	        let to_exclude = resolve_selector_to_tasks(
66	            &engine,
67	            selector,
68	            pkg_dep_graph,
69	            scm,
70	            repo_root,
71	            global_deps,
72	        )?;
73	        included_tasks.retain(|t| !to_exclude.contains(t));
74	    }
75	
76	    if included_tasks.is_empty() {
77	        return Ok(engine.retain_affected_tasks(&included_tasks));
78	    }
79	
80	    // retain_affected_tasks expands to transitive dependents and prunes the
81	    // rest, which is exactly what we want — downstream tasks of matched tasks
82	    // still need to run.
83	    Ok(engine.retain_affected_tasks(&included_tasks))
84	}
