386	    fn make_engine(
387	        tasks: &[(TaskId<'static>, TaskDefinition)],
388	        edges: &[(TaskId<'static>, TaskId<'static>)],
389	    ) -> Engine {
390	        let mut engine: Engine<Building> = Engine::new();
391	        for (task_id, def) in tasks {
392	            engine.get_index(task_id);
393	            engine.add_definition(task_id.clone(), def.clone());
394	        }
395	        for (from, to) in edges {
396	            let from_idx = engine.get_index(from);
397	            let to_idx = engine.get_index(to);
398	            engine.task_graph_mut().add_edge(from_idx, to_idx, ());
399	        }
400	        engine.seal()
401	    }
