#[test]
    fn retain_is_idempotent() {
        let engine = build_linear_engine();
        let affected: HashSet<_> = [TaskId::new("b", "build")].into_iter().collect();
        let engine = engine.retain_affected_tasks(&affected);
        let ids_first = task_ids_set(&engine);

        // Second call with same affected set should be idempotent.
        let engine = engine.retain_affected_tasks(&affected);
        let ids_second = task_ids_set(&engine);

        assert_eq!(ids_first, ids_second, "retain should be idempotent");
    }

    /// Regression test: when a task is affected, its dependencies (the tasks
    /// the affected task declares via `dependsOn`) must also be retained.
    /// This reproduces the `affectedUsingTaskInputs` bug where `^build`
    /// dependencies were dropped because only reverse DFS (dependents) was
    /// performed, not forward DFS (dependencies).
    ///
    /// Graph: web#build → common#build  (web depends on common via ^build)
    /// Only web's source changed → web#build is affected.
    /// common#build must also be retained because web#build needs it.
    #[test]
    fn affected_task_retains_dependencies() {
        let mut engine: Engine<Building> = Engine::new();

        let web_build = TaskId::new("web", "build");
        let common_build = TaskId::new("common", "build");

        let web_idx = engine.get_index(&web_build);
        let common_idx = engine.get_index(&common_build);

        engine.add_definition(web_build.clone(), TaskInfo::default());
        engine.add_definition(common_build.clone(), TaskInfo::default());

        // web#build depends on common#build (edge direction: web → common)
        engine.task_graph_mut().add_edge(web_idx, common_idx, ());

        engine.connect_to_root(&common_build);

        let engine = engine.seal();

        // Only web#build's input changed, so it's the "affected" task.
        let affected: HashSet<_> = [web_build.clone()].into_iter().collect();
        let engine = engine.retain_affected_tasks(&affected);

        let ids = task_ids_set(&engine);
        assert!(
            ids.contains(&web_build),
            "affected web#build must be retained: {ids:?}"
        );
        assert!(
            ids.contains(&common_build),
            "common#build (a dependency of web#build) must also be retained: {ids:?}"
        );
        assert_eq!(ids.len(), 2, "both web#build and common#build should survive: {ids:?}");
    }

    /// Variant of the dependency retention test with a longer chain:
    /// app#build → lib#build → base#build
    /// Only app's source changed → app#build is affected.
    /// Both lib#build and base#build must be retained.
    #[test]
    fn affected_task_retains_transitive_dependencies() {
        let mut engine: Engine<Building> = Engine::new();

        let app_build = TaskId::new("app", "build");
        let lib_build = TaskId::new("lib", "build");
        let base_build = TaskId::new("base", "build");

        let app_idx = engine.get_index(&app_build);
        let lib_idx = engine.get_index(&lib_build);
        let base_idx = engine.get_index(&base_build);

        engine.add_definition(app_build.clone(), TaskInfo::default());
        engine.add_definition(lib_build.clone(), TaskInfo::default());
        engine.add_definition(base_build.clone(), TaskInfo::default());

        // app → lib → base
        engine.task_graph_mut().add_edge(app_idx, lib_idx, ());
        engine.task_graph_mut().add_edge(lib_idx, base_idx, ());

        engine.connect_to_root(&base_build);

        let engine = engine.seal();

        let affected: HashSet<_> = [app_build.clone()].into_iter().collect();
        let engine = engine.retain_affected_tasks(&affected);

        let ids = task_ids_set(&engine);
        assert!(ids.contains(&app_build), "app#build must be retained: {ids:?}");
        assert!(ids.contains(&lib_build), "lib#build must be retained: {ids:?}");
        assert!(ids.contains(&base_build), "base#build must be retained: {ids:?}");
        assert_eq!(ids.len(), 3, "all three should survive: {ids:?}");
    }

    /// Diamond graph where affected task depends on multiple branches:
    /// d → b, d → c, b → a, c → a
    /// Only d is affected — all of b, c, a must be retained.
    #[test]
    fn affected_task_retains_dependencies_diamond() {
        let mut engine: Engine<Building> = Engine::new();

        let a = TaskId::new("a", "build");
        let b = TaskId::new("b", "build");
        let c = TaskId::new("c", "build");
        let d = TaskId::new("d", "build");

        let a_idx = engine.get_index(&a);
        let b_idx = engine.get_index(&b);
        let c_idx = engine.get_index(&c);
        let d_idx = engine.get_index(&d);

        engine.add_definition(a.clone(), TaskInfo::default());
        engine.add_definition(b.clone(), TaskInfo::default());
        engine.add_definition(c.clone(), TaskInfo::default());
        engine.add_definition(d.clone(), TaskInfo::default());

        // d → b, d → c, b → a, c → a
        engine.task_graph_mut().add_edge(d_idx, b_idx, ());
        engine.task_graph_mut().add_edge(d_idx, c_idx, ());
        engine.task_graph_mut().add_edge(b_idx, a_idx, ());
        engine.task_graph_mut().add_edge(c_idx, a_idx, ());

        engine.connect_to_root(&a);

        let engine = engine.seal();

        let affected: HashSet<_> = [d.clone()].into_iter().collect();
        let engine = engine.retain_affected_tasks(&affected);

        let ids = task_ids_set(&engine);
        assert!(ids.contains(&a), "a#build must be retained: {ids:?}");
        assert!(ids.contains(&b), "b#build must be retained: {ids:?}");
        assert!(ids.contains(&c), "c#build must be retained: {ids:?}");
        assert!(ids.contains(&d), "d#build must be retained: {ids:?}");
        assert_eq!(ids.len(), 4, "all four should survive: {ids:?}");
    }
}

