309	    /// Returns a new engine containing only the given directly affected tasks
310	    /// and their transitive dependents. Used for task-level `--affected`
311	    /// detection: the caller determines which tasks' `inputs` match the changed
312	    /// files, then this method expands that set to include downstream tasks and
313	    /// prunes everything else.
314	    ///
315	    /// This consumes and returns a new engine rather than mutating in place,
316	    /// consistent with `create_engine_for_subgraph` and the sealed typestate
317	    /// contract. Must be called during build, before the engine is shared
318	    /// via `Arc` or handed to the executor.
319	    pub fn retain_affected_tasks(mut self, affected_tasks: &HashSet<TaskId>) -> Self {
320	        let entrypoint_indices: Vec<_> = affected_tasks
321	            .iter()
322	            .filter_map(|task_id| self.task_lookup.get(task_id))
323	            .copied()
324	            .collect();
325	
326	        let mut reachable = HashSet::new();
327	        reachable.insert(self.root_index);
328	        depth_first_search(Reversed(&self.task_graph), entrypoint_indices, |event| {
329	            if let DfsEvent::Discover(n, _) = event {
330	                reachable.insert(n);
331	            }
332	        });
333	
334	        self.task_graph = self.task_graph.filter_map(
335	            |node_idx, node| {
336	                if reachable.contains(&node_idx) {
337	                    Some(node.clone())
338	                } else {
339	                    None
340	                }
341	            },
342	            |_, _| Some(()),
343	        );
344	
345	        // Rebuild all metadata from the pruned graph. root_index is recovered
346	        // during the task_lookup rebuild to avoid a separate linear scan.
347	        let mut new_root_index = None;
348	        self.task_lookup = self
349	            .task_graph
350	            .node_indices()
351	            .filter_map(|index| {
352	                match self
353	                    .task_graph
354	                    .node_weight(index)
355	                    .expect("node index should be present")
356	                {
357	                    TaskNode::Root => {
358	                        new_root_index = Some(index);
359	                        None
360	                    }
361	                    TaskNode::Task(task) => Some((task.clone(), index)),
362	                }
363	            })
364	            .collect();
365	        self.root_index = new_root_index.expect("root node should be present");
366	
367	        self.task_definitions
368	            .retain(|id, _| self.task_lookup.contains_key(id));
369	        self.task_locations
370	            .retain(|id, _| self.task_lookup.contains_key(id));
