/// Returns a new engine containing only the given directly affected tasks,
    /// their transitive dependents, and their transitive dependencies. Used
    /// for task-level `--affected` detection: the caller determines which tasks'
    /// `inputs` match the changed files, then this method expands that set to
    /// include both downstream tasks (dependents) and upstream tasks
    /// (dependencies, e.g. `^build` topological deps) and prunes everything else.
    ///
    /// This consumes and returns a new engine rather than mutating in place,
    /// consistent with `create_engine_for_subgraph` and the sealed typestate
    /// contract. Must be called during build, before the engine is shared
    /// via `Arc` or handed to the executor.
    pub fn retain_affected_tasks(mut self, affected_tasks: &HashSet<TaskId>) -> Self {
        let entrypoint_indices: Vec<_> = affected_tasks
            .iter()
            .filter_map(|task_id| self.task_lookup.get(task_id))
            .copied()
            .collect();

        let mut reachable = HashSet::new();
        reachable.insert(self.root_index);

        // Reverse DFS: find all tasks that depend on the affected tasks
        // (transitive dependents — things that must also run because they
        // consume the affected tasks' outputs).
        let mut dep_indices = entrypoint_indices.clone();
        depth_first_search(Reversed(&self.task_graph), &dep_indices, |event| {
            if let DfsEvent::Discover(n, _) = event {
                reachable.insert(n);
            }
        });

        // Forward DFS: find all tasks that the affected tasks depend on
        // (transitive dependencies — things like `^build` topological deps
        // that must run before the affected tasks, or their outputs won't
        // exist on a cold cache).
        depth_first_search(&self.task_graph, entrypoint_indices, |event| {
            if let DfsEvent::Discover(n, _) = event {
                reachable.insert(n);
            }
        });

